 166→function CompactCard({
 167→  idea,
 168→  index,
 169→  onClick,
 170→  isSaved,
 171→  onToggleSave,
 172→  showBookmark,
 173→}: {
 174→  idea: IdeaBrief;
 175→  index: number;
 176→  onClick: () => void;
 177→  isSaved: boolean;
 178→  onToggleSave: (saved: boolean) => void;
 179→  showBookmark: boolean;
 180→}) {
 181→  const delay = Math.min(index, 8) * 150;
 182→
 183→  // Deduplicated source platforms
 184→  const sourcePlatforms: Platform[] = useMemo(() => {
 185→    if (!idea.sources || idea.sources.length === 0) return [];
 186→    const seen = new Set<Platform>();
 187→    return idea.sources.reduce<Platform[]>((acc, s) => {
 188→      if (isPlatform(s.platform) && !seen.has(s.platform)) {
 189→        seen.add(s.platform);
 190→        acc.push(s.platform);
 191→      }
 192→      return acc;
 193→    }, []);
 194→  }, [idea.sources]);
 195→
 196→  return (
 197→    <article
 198→      onClick={onClick}
 199→      onKeyDown={(e) => {
 200→        if (e.key === "Enter" || e.key === " ") {
 201→          e.preventDefault();
 202→          onClick();
 203→        }
 204→      }}
 205→      tabIndex={0}
 206→      role="button"
 207→      aria-label={`View idea: ${idea.name}`}
 208→      className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-700 p-5 cursor-pointer hover:-translate-y-1 hover:shadow-xl hover:border-primary-400 dark:hover:border-primary-500 focus:outline-none focus:ring-2 focus:ring-primary-500 focus:ring-offset-2 dark:focus:ring-offset-gray-900 transition-all duration-200 animate-fade-in-up opacity-0"
 209→      style={{ animationDelay: `${delay}ms`, animationFillMode: "forwards" }}
 210→    >
 211→      {/* Top: score circle + name + bookmark */}
 212→      <div className="flex items-center gap-3 mb-2">
 213→        <div
 214→          className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-bold ${getScoreCircleColor(idea.priorityScore)}`}
 215→        >
 216→          {idea.priorityScore.toFixed(0)}
 217→        </div>
 218→        <h3 className="font-mono text-sm font-bold text-gray-900 dark:text-white truncate flex-1">
 219→          {idea.name}
 220→        </h3>
 221→        {showBookmark && (
 222→          <BookmarkButton
 223→            ideaId={idea.id}
 224→            initialSaved={isSaved}
 225→            onToggle={onToggleSave}
 226→            size="sm"
 227→          />
 228→        )}
 229→      </div>
 230→
 231→      {/* Tagline */}
 232→      <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-2 mb-3">
 233→        {idea.tagline}
 234→      </p>
 235→
 236→      {/* Source badges + relative date */}
 237→      {(sourcePlatforms.length > 0 || idea.generatedAt) && (
 238→        <div className="flex items-center justify-between gap-2 mb-3">
 239→          <div className="flex items-center gap-1">
 240→            {sourcePlatforms.map((p) => (
 241→              <MiniPlatformBadge key={p} platform={p} />
 242→            ))}
 243→          </div>
 244→          {idea.generatedAt && (
 245→            <span className="text-[11px] text-gray-400 dark:text-gray-500 whitespace-nowrap">
 246→              {relativeTime(idea.generatedAt)}
 247→            </span>
 248→          )}
 249→        </div>
 250→      )}
 251→
 252→      {/* Bottom: effort badge + revenue */}
 253→      <div className="flex items-center justify-between gap-2 min-w-0">
 254→        <span
 255→          className={`inline-flex items-center text-xs font-medium px-2 py-0.5 rounded-full flex-shrink-0 ${getEffortBadgeColor(idea.effortEstimate)}`}
 256→        >
 257→          {getEffortLabel(idea.effortEstimate)}
 258→        </span>
 259→        <span
 260→          title={humanizeText(idea.revenueEstimate)}
 261→          className="text-xs font-medium text-emerald-700 dark:text-emerald-300 truncate min-w-0"
 262→        >
 263→          {humanizeText(idea.revenueEstimate)}
 264→        </span>
 265→      </div>
 266→    </article>
 267→  );
 268→}
